"use client";

import { Category, Dish, MenuForm, } from "@/data/types/dishMenu";
import { Box, Button, Flex, TextArea, TextField } from "@radix-ui/themes";
import { useFieldArray, useForm, UseFormReturn, useWatch } from "react-hook-form";
import InputLabel from "./label/InputLabel";
import ErrorLabel from "./label/ErrorLabel";

type FormCategoryProps = {
    form: UseFormReturn<MenuForm, any, MenuForm>,
    index: number,
    category: Category
    onRemoveCategory: () => void
}

const CategoryForm = ({ form, index, category, onRemoveCategory }: FormCategoryProps) => {
    const { control, register, formState: { errors }, handleSubmit } = form
    const {
        append,
        remove: removeDish,
        fields: dishes } = useFieldArray({
            name: `categories.${index}.dishes`,
            control
        })


    const onAddNewDish = () => {
        const newDish: Dish = {
            id: crypto.randomUUID(),
            name: "",
            price: null,
            description: ""
        }
        append(newDish)
    }

    return <Flex key={category.id} direction="column" gap="2" className="p-5 m-2 border rounded-md" >

        <Box >
            <div className="flex flex-row items-center gap-2 p-2">
                <TextField.Root
                    key={category.id}
                    {...register(`categories.${index}.name`)}
                    size="3"
                    placeholder="Kategoria:"
                    variant="soft"
                    color="green"
                />
                <Button
                    type="button"
                    color="red"
                    onClick={onRemoveCategory}
                    size="3">
                    Usuń kategorię
                </Button>
            </div>
        </Box>
        {dishes.map((dish, indexDish) => (<div key={dish.id} >
            <div className="flex items-start gap-6">
                <Box className="flex-1">
                    <TextField.Root
                        color="jade"
                        variant="classic"
                        placeholder="Wpisz nazwe dania.."
                        {...register(`categories.${index}.dishes.${indexDish}.name`, {
                            required: true,
                            minLength: { value: 3, message: "Nazwa dania musi mieć minimum 3 litery" },
                        })}
                    />

                    {errors.categories?.[index]?.dishes?.[indexDish]?.name && (
                        <p style={{ color: "green", fontSize: "12px", marginTop: "4px" }}>
                            {errors.categories?.[index]?.dishes?.[indexDish]?.name?.message}
                        </p>
                    )}
                </Box>


                <div className="flex items-start justify-end gap-2">
                    <Box maxWidth="200px">
                        <TextField.Root
                            placeholder="Cena"
                            {...register(`categories.${index}.dishes.${indexDish}.price`, {
                                required: true,
                                min: { value: 1, message: "Minimalna cena musi być większa od 0" },
                            })}
                        />

                        <p style={{ color: "green", fontSize: "12px", marginTop: "4px" }}>
                            {errors.categories?.[index]?.dishes?.[indexDish]?.price?.message}
                        </p>
                    </Box>

                    <Box>
                        <Button type="button" onClick={() => removeDish(indexDish)}>
                            Usuń danie
                        </Button>
                    </Box>
                </div>
            </div>
            <div>
            </div>



        </div>))}
        <Box>
            <Button color="gold" m="1" type="button" onClick={onAddNewDish}>
                Dodaj danie
            </Button>
            <Button type="button" m="1" color="red" onClick={onRemoveCategory}>
                Usuń kategorię
            </Button>
        </Box>


    </Flex>
}

export default CategoryForm